// Generated by AI Assistant

import { BackupStatus } from '@eclipse-che/common';
import { Icon, Label, LabelProps } from '@patternfly/react-core';
import {
  CheckCircleIcon,
  ExclamationTriangleIcon,
  InfoCircleIcon,
  InProgressIcon,
  OutlinedClockIcon,
} from '@patternfly/react-icons';
import React from 'react';

import styles from '@/components/BackupStatusBadge/index.module.css';
import { CheTooltip } from '@/components/CheTooltip';
import { formatDate } from '@/services/helpers/dates';

export type Props = {
  status: BackupStatus;
  lastBackupTime?: string;
  backupImageUrl?: string;
};

const BACKUP_STATUS_LABELS: Record<BackupStatus, string> = {
  [BackupStatus.SUCCESS]: 'Success',
  [BackupStatus.FAILED]: 'Failed',
  [BackupStatus.IN_PROGRESS]: 'In Progress',
  [BackupStatus.NEVER]: 'Never',
  [BackupStatus.UNAVAILABLE]: 'Unavailable',
};

const STATUS_COLORS: Record<BackupStatus, LabelProps['color']> = {
  [BackupStatus.SUCCESS]: 'green',
  [BackupStatus.FAILED]: 'orange',
  [BackupStatus.IN_PROGRESS]: 'blue',
  [BackupStatus.NEVER]: 'grey',
  [BackupStatus.UNAVAILABLE]: 'grey',
};

function getStatusIcon(status: BackupStatus): React.ReactElement {
  switch (status) {
    case BackupStatus.SUCCESS:
      return (
        <Icon status="success" isInline>
          <CheckCircleIcon />
        </Icon>
      );
    case BackupStatus.FAILED:
      return (
        <Icon status="warning" isInline>
          <ExclamationTriangleIcon />
        </Icon>
      );
    case BackupStatus.IN_PROGRESS:
      return (
        <Icon status="info" isInline>
          <InProgressIcon className={styles.rotate} aria-label="Backup in progress" />
        </Icon>
      );
    case BackupStatus.NEVER:
      return (
        <Icon status="custom" isInline>
          <InfoCircleIcon />
        </Icon>
      );
    case BackupStatus.UNAVAILABLE:
      return (
        <Icon status="custom" isInline>
          <OutlinedClockIcon />
        </Icon>
      );
  }
}

function getTooltipContent(
  status: BackupStatus,
  lastBackupTime?: string,
  backupImageUrl?: string,
): React.ReactElement {
  const lines: string[] = [`Status: ${BACKUP_STATUS_LABELS[status]}`];

  if (lastBackupTime) {
    const date = new Date(lastBackupTime);
    lines.push(`Last backup: ${formatDate(date)}`);
  }

  if (backupImageUrl) {
    lines.push(`Image: ${backupImageUrl}`);
  }

  if (status === BackupStatus.NEVER) {
    lines.push('This workspace has never been backed up.');
  } else if (status === BackupStatus.UNAVAILABLE) {
    lines.push('Backup image is not yet available. A backup job has not completed.');
  }

  return (
    <div data-testid="backup-status-tooltip-content">
      {lines.map((line, index) => (
        <div key={index}>{line}</div>
      ))}
    </div>
  );
}

export function BackupStatusBadge(props: Props): React.ReactElement {
  const { status, lastBackupTime, backupImageUrl } = props;

  const color = STATUS_COLORS[status];
  const icon = getStatusIcon(status);
  const tooltipContent = getTooltipContent(status, lastBackupTime, backupImageUrl);

  const sizeClassName = styles['size-md'] || '';
  const className = `${styles.backupStatusBadge} ${sizeClassName}`.trim();

  const statusLabel = BACKUP_STATUS_LABELS[status];

  return (
    <CheTooltip content={tooltipContent}>
      <Label
        className={className}
        color={color}
        icon={icon}
        data-testid="backup-status-badge"
        aria-label={`Backup status: ${statusLabel}`}
      >
        {statusLabel}
      </Label>
    </CheTooltip>
  );
}
